// L172-181: QuickExamPluginAPI 接口要求 ──────
export interface QuickExamPluginAPI {
  app: App;
  callBackendJson(
    endpoint: string, label: string,
    body: Record<string, unknown>,
    method?: "GET" | "POST",
  ): Promise<unknown | null>;          // ⚠️ 接口要求, 返回 JSON
  inferCurrentVaultId(): string;       // ⚠️ 接口要求, 返回 vault_id
}

// L190-272: QuickExamController 类实现 (节选) ──────
export class QuickExamController {
  private sessions = new Map<string, ExamSession>();
  constructor(private plugin: QuickExamPluginAPI) {}

  async startExam(NoticeCtor: typeof import("obsidian").Notice): Promise<void> {
    const active = this.plugin.app.workspace.getActiveFile();
    if (!active) {
      new NoticeCtor("请先打开你想考察的节点 (节点/<concept>.md)", 5000);
      return;
    }
    if (!active.path.startsWith("节点/") || active.basename.startsWith("考察-")) {
      new NoticeCtor("考察命令需在 节点/<concept>.md 上触发", 5000);
      return;
    }

    const concept = active.basename;
    new NoticeCtor("🤔 正在生成题目...", 3000);

    const resp = await this.plugin.callBackendJson(
      "/api/v1/exam/quick",
      `生成 "${concept}" 的考察题`,
      { node_id: concept, vault_id: this.plugin.inferCurrentVaultId() },
      "POST",
    );
    if (!resp) return;
    // ... 创建 节点/考察-{concept}-{date}.md, register session, openLinkText
  }

  async onFileModified(file: TFile, NoticeCtor: ...): Promise<void> {
    const session = this.sessions.get(file.path);
    if (!session || session.graded) return;
    // ... extract answer → POST /api/v1/exam/grade → 文件底部追加反馈
  }
}

// L1352: 主类的 callBackend 方法签名 (非 JSON, 直接吞返回值并发 Notice)
private async callBackend(
  endpoint: string,
  label: string,
  body?: Record<string, unknown>,
  method: "GET" | "POST" = "POST",
): Promise<void>   // ⚠️ 注意: 返回 Promise<void> 不是 Promise<unknown|null>

// grep "callBackendJson|inferCurrentVaultId|inferVaultId" /src/main.ts → 0 matches
// 主类既没 callBackendJson, 也没 inferCurrentVaultId — 直接 `new QuickExamController(this)` 会 TS error

// T7. main.ts 已 wire QuickExam (spec-as-test) ──────
describe("main_ts_wires_quick_exam", () => {
  const mainPath = join(process.cwd(), "src", "main.ts");
  const mainTs = readFileSync(mainPath, "utf-8");

  test("import QuickExamController from ./exam-quick", () => {
    assert.match(mainTs,
      /import\s*\{\s*QuickExamController\s*\}\s*from\s*["']\.\/exam-quick["']/,
      "main.ts 必须 import QuickExamController");
  });

  test("import inferVaultId from ./error-candidate-helpers", () => {
    assert.match(mainTs,
      /import\s*\{\s*inferVaultId\s*\}\s*from\s*["']\.\/error-candidate-helpers["']/);
  });

  test("onload new QuickExamController + 接 callBackend 闭包", () => {
    assert.match(mainTs,
      /new\s+QuickExamController\s*\(\s*\{[\s\S]{0,400}?callBackendJson[\s\S]{0,200}?this\.callBackend/,
      "main.ts 必须 new QuickExamController 并把 callBackendJson 绑到 this.callBackend");
  });

  test("addCommand 注册 canvas:start-quick-exam", () => {
    assert.match(mainTs,
      /id:\s*["']canvas:start-quick-exam["']/,
      "命令 ID canvas:start-quick-exam 未注册 — 命令面板看不到 Quick Exam");
  });

  test("命令 callback 调 quickExam.startExam(Notice)", () => {
    assert.match(mainTs,
      /quickExam\.startExam\s*\(\s*Notice\s*\)/);
  });

  test("vault.on('modify') 分发到 quickExam.onFileModified", () => {
    assert.match(mainTs, /vault\.on\s*\(\s*["']modify["']/);
  });
});

// ⚠️ 当前状态: 这 6 个 assertion 全部应 fail (因为 main.ts 0 matches)
