➕ 新增 ~15 行实例化 + addCommand. 因 main.ts 的 callBackend 返回 void, 需用闭包适配为 callBackendJson 返回 unknown|null:

this.quickExam = new QuickExamController({
  app: this.app,
  callBackendJson: async (endpoint, label, body, method) => {
    // 适配主类 callBackend: 主类发 Notice 后吞返回值, 这里需要 JSON
    // 需要审查: 是否应该把 main.ts callBackend 改返回 unknown|null,
    // 而不是写适配闭包? (减少分叉)
    return await this.callBackendForJson(endpoint, label, body, method);
  },
  inferCurrentVaultId: () => inferVaultId(this.app),
});

this.addCommand({
  id: "canvas:start-quick-exam",
  name: "Quick Exam (单题快速考察, MVP-α)",
  hotkeys: [{ modifiers: ["Mod", "Shift"], key: "Q" }],
  callback: () => this.quickExam.startExam(Notice),
});

this.registerEvent(
  this.app.vault.on("modify", (file) => {
    if (file instanceof TFile) this.quickExam.onFileModified(file, Notice);
  }),
);

